import{_ as i,C as n,o as l,c as d,j as t,a,E as o,ag as s}from"./chunks/framework.DLWhSH9p.js";const k=JSON.parse('{"title":"Marketplace","description":"","frontmatter":{},"headers":[],"relativePath":"guide/marketplace.md","filePath":"guide/marketplace.md"}'),c={name:"guide/marketplace.md"};function h(g,e,p,m,u,b){const r=n("SchemeImage");return l(),d("div",null,[e[0]||(e[0]=t("h1",{id:"marketplace",tabindex:"-1"},[a("Marketplace "),t("a",{class:"header-anchor",href:"#marketplace","aria-label":'Permalink to "Marketplace"'},"​")],-1)),e[1]||(e[1]=t("p",null,"The Marketplace is where you hire voice actors, musicians, on-camera spokespersons, editors, and animators for your channel — and, if you're a creator, where you list yourself for hire.",-1)),e[2]||(e[2]=t("p",null,[a("It runs as a standalone app at "),t("strong",null,[t("a",{href:"https://marketplace.mossworks.io/",target:"_blank",rel:"noreferrer"},"marketplace.mossworks.io")]),a(" and is reachable from CRAFT via the "),t("code",null,"craft ↗"),a(" link in the top-right of the marketplace chrome (and vice versa).")],-1)),o(r,{name:"marketplace-browse",alt:"Marketplace browse"}),e[3]||(e[3]=s('<h2 id="the-pricing-model" tabindex="-1">The pricing model <a class="header-anchor" href="#the-pricing-model" aria-label="Permalink to &quot;The pricing model&quot;">​</a></h2><p>The Marketplace&#39;s defining commitment: <strong>sellers pay $0 in platform fees</strong>. Buyers pay a flat <strong>15% marketplace fee</strong> on top of the seller&#39;s quoted price, and that&#39;s it — no card fees layered in, no hidden cuts on the seller side.</p><p>Storage is the only line item creators ever see. It scales with the library they upload — enough to prevent abuse, not enough to matter in practice ($4/mo for 25 GB at the current tier). Listings, demos, messaging, contracts, payouts (via Stripe Connect Express), and 1099 issuance are all free.</p><h2 id="sub-views" tabindex="-1">Sub-views <a class="header-anchor" href="#sub-views" aria-label="Permalink to &quot;Sub-views&quot;">​</a></h2><p>The Marketplace&#39;s top nav has exactly four tabs: <strong>Browse · Gigs · Brand partners · My Studio</strong>.</p><h3 id="browse" tabindex="-1">Browse <a class="header-anchor" href="#browse" aria-label="Permalink to &quot;Browse&quot;">​</a></h3><p>Filter rail on the left (category, style/vibe, language, turnaround, price), hero stats, a <strong>Spotlight rail</strong> of top creators (≥ 4.8★ with ≥ 25 completed jobs in any role), then a grid of everyone else. Each card shows role, rating, jobs completed, rate, and — for voice actors — a mini-waveform demo or filmstrip preview.</p><p><strong>Categories</strong></p><ul><li><strong>Voice actors</strong> — narration, spokesperson, ad reads</li><li><strong>Spokespersons</strong> — on-camera hosts</li><li><strong>Musicians</strong> — custom tracks, ambient, orchestral, electronic</li><li><strong>Editors</strong> — pacing surgery, shorts-first cuts, long-form docs</li><li><strong>Animators</strong> — 2D motion, 3D, explainer, data-viz</li></ul><h3 id="gigs" tabindex="-1">Gigs <a class="header-anchor" href="#gigs" aria-label="Permalink to &quot;Gigs&quot;">​</a></h3>',10)),o(r,{name:"marketplace-gigs",alt:"Open gigs — filter rail + gig cards"}),e[4]||(e[4]=s('<p>Gigs is the flip side of Browse — instead of buyers searching for creators, creators see <strong>channels posting what they need</strong> and apply with a message + quote.</p><p><strong>For creators</strong></p><ol><li>Open <strong>Gigs</strong> in the marketplace top nav.</li><li>Filter by role, budget, deadline, status.</li><li>Click a gig card to see the full brief (description, deliverables, tags, budget).</li><li>Submit an application — short pitch + your quote.</li></ol><p>The buyer sees your application under their gig. If they shortlist or accept you, the next step is the standard <a href="#hire-contract">Hire &amp; contract</a> flow against your quote.</p><p><strong>For buyers — Post a gig</strong></p>',5)),o(r,{name:"marketplace-post-gig",alt:"Post a gig form with live preview"}),e[5]||(e[5]=s('<p>Click <strong>+ Post a gig</strong> in the top-right of the marketplace chrome. The form has:</p><ul><li><strong>Title</strong> — the headline creators see in the list</li><li><strong>Role</strong> — voice / spokesperson / music / editor / animator</li><li><strong>Description</strong> — the brief (context, tone, samples, deadlines)</li><li><strong>Deliverables</strong> — file formats, revisions, timeline</li><li><strong>Budget min / max</strong> — displayed as a range on the card</li><li><strong>Deadline</strong> — free-text (e.g. &quot;Apr 28&quot; or &quot;Ongoing&quot;)</li><li><strong>Tags</strong> — comma-separated search keywords</li><li><strong>Your name / channel</strong> — attribution shown on the gig</li></ul><p>A live preview card sits to the right so you can see the cards as applicants will. Nothing is charged at post-time — funds only move through escrow once you <strong>accept</strong> a specific applicant.</p><h3 id="brand-partners" tabindex="-1">Brand partners <a class="header-anchor" href="#brand-partners" aria-label="Permalink to &quot;Brand partners&quot;">​</a></h3><div class="info custom-block"><p class="custom-block-title">Coming soon</p><p>Brand-partner listings, two-sided reviews, and placement matching ship in the next phase. The tab renders a coming-soon slide today with placeholder partner cards behind a gradient veil so you can preview the IA.</p></div><p>Brand partners is the <strong>brand-sponsorship</strong> side of the Marketplace — distinct from creators-for-hire. Two populations will live here:</p><ul><li><strong>Channels seeking sponsors</strong> — audience, niche, sample reads, CPM ranges</li><li><strong>Brands seeking channels</strong> — products, campaigns, deliverable expectations, budgets</li></ul><p>Both rendered as partner cards with hue-themed covers, tier badges (see <a href="#gamification-tiers-badges-streaks">Gamification</a>), active listings count, and a spotlight flag for top performers. Reviews are <strong>placement-scoped</strong>, not gig-scoped — they reference a specific placement ID so both sides can back-reference the engagement. Same star-rating mechanics as creator reviews, same merit-only ranking — no paid boosts.</p><h3 id="artist-profile" tabindex="-1">Artist profile <a class="header-anchor" href="#artist-profile" aria-label="Permalink to &quot;Artist profile&quot;">​</a></h3><p>Cover image, demo reel with inline audio playback, reviews, and a sticky hire sidebar. The sidebar has:</p><ul><li>Headline rate</li><li>Minimum order &amp; typical reply time</li><li>Package tiers (e.g. &quot;Script under 500w · 24h · $60&quot;, &quot;Documentary narration · 3 days · $210&quot;)</li><li><strong>Request this creator →</strong> (starts the hire flow)</li><li><strong>Send a message first</strong> (real messaging — not mocked)</li></ul><h3 id="my-studio" tabindex="-1">My Studio <a class="header-anchor" href="#my-studio" aria-label="Permalink to &quot;My Studio&quot;">​</a></h3><p>If you&#39;re a creator, this is your home. The page mirrors the craft team&#39;s design mock with three layers:</p><p><strong>Hero row</strong> — <code>ProgressionTile</code> on the left (your tier badge, tier-score progress bar, top earned badges, active streak, recent achievements, onboarding completeness) + <code>SpotlightCard</code> on the right (this-quarter job progress against the goal, per-role eligibility breakdown, contribution weights — rating 40% / on-time 30% / volume 20% / reply 10%).</p><p><strong>Five-stat grid</strong> — 90-day rating, active gigs, completed gigs, this-quarter progress, setup completion (X/21).</p><p><strong>Three internal tabs</strong></p><ul><li><strong>Metrics</strong> (default) — earned + locked badges with show/hide toggle, and your most recent reviews.</li><li><strong>Active gigs</strong> — table of in-progress contracts with status, deadline, amount. Click a row for the full state-machine view.</li><li><strong>Partnerships</strong> — placeholder for &quot;Brands I worked with&quot; with a &quot;Leave review&quot; button per partner once the brand-partners backend lands.</li></ul><p><strong>Quick links rail</strong> at the bottom — Profile · Demos · Packages · Availability · Stripe · Storage · Invitations · Applications · Contracts · Disputes. These were top-level tabs in the previous IA; now they live here as one-click jumps so the top nav stays clean.</p><h2 id="gamification-tiers-badges-streaks" tabindex="-1">Gamification: tiers, badges, streaks <a class="header-anchor" href="#gamification-tiers-badges-streaks" aria-label="Permalink to &quot;Gamification: tiers, badges, streaks&quot;">​</a></h2><p>Creators and brand partners earn <strong>visible, criterion-based recognition</strong> based on their public stats. Nothing here is pay-to-play — tiers and badges are computed from <code>rating</code>, <code>jobsCompleted</code>, <code>onTimePct</code>, and <code>replyHours</code>. The rationale for every badge is visible in the UI, so there&#39;s no mystery about what unlocked it.</p><h3 id="tiers" tabindex="-1">Tiers <a class="header-anchor" href="#tiers" aria-label="Permalink to &quot;Tiers&quot;">​</a></h3><p>Four tiers, gated on hard thresholds — all three criteria must be met to advance:</p><table tabindex="0"><thead><tr><th>Tier</th><th style="text-align:right;">Rating</th><th style="text-align:right;">Completed jobs</th><th style="text-align:right;">On-time</th></tr></thead><tbody><tr><td><strong>Bronze</strong></td><td style="text-align:right;">—</td><td style="text-align:right;">—</td><td style="text-align:right;">—</td></tr><tr><td><strong>Silver</strong></td><td style="text-align:right;">≥ 4.5</td><td style="text-align:right;">≥ 10</td><td style="text-align:right;">≥ 90%</td></tr><tr><td><strong>Gold</strong></td><td style="text-align:right;">≥ 4.8</td><td style="text-align:right;">≥ 50</td><td style="text-align:right;">≥ 95%</td></tr><tr><td><strong>Platinum</strong></td><td style="text-align:right;">≥ 4.9</td><td style="text-align:right;">≥ 150</td><td style="text-align:right;">≥ 98%</td></tr></tbody></table><p>The profile card also shows a <code>tierScore</code> (0–100): <strong>40% rating · 30% volume · 20% on-time · 10% reply speed</strong>. It&#39;s a smooth signal between tier jumps so progress is legible.</p><h3 id="badges" tabindex="-1">Badges <a class="header-anchor" href="#badges" aria-label="Permalink to &quot;Badges&quot;">​</a></h3><p>Badges are <strong>current-state</strong> flags — they turn on and off as stats move. Examples: <code>Spotlight eligible</code> (≥ 4.8★ + ≥ 25 jobs), <code>Fast replier</code> (avg reply ≤ 3h), <code>Multilingual</code> (two or more delivery languages), <code>Veteran</code> (100+ completed jobs). Each badge lists its rationale on hover so there&#39;s no guesswork.</p><h3 id="achievements" tabindex="-1">Achievements <a class="header-anchor" href="#achievements" aria-label="Permalink to &quot;Achievements&quot;">​</a></h3><p>Achievements are <strong>permanent</strong> milestones — once unlocked, they stay. Rarity tiers: <code>common</code> · <code>uncommon</code> · <code>rare</code> · <code>legendary</code>. Examples: <code>First gig delivered</code>, <code>First repeat client</code>, <code>Five-gig streak</code>, <code>Spotlighted 3 weeks</code>, <code>100 gigs completed</code>. Unlocks show the date in the profile&#39;s achievements strip.</p><h3 id="streaks" tabindex="-1">Streaks <a class="header-anchor" href="#streaks" aria-label="Permalink to &quot;Streaks&quot;">​</a></h3><p>Streaks are <strong>consecutive counters</strong> that reset when broken but remain visible as historical markers. Examples: <code>On-time streak · 47 days</code>, <code>Five-star streak · 6 deliveries</code>, <code>Reply-time streak · 21 days</code>. An inactive streak renders muted to show the last peak.</p><h3 id="next-tier-hint" tabindex="-1">Next-tier hint <a class="header-anchor" href="#next-tier-hint" aria-label="Permalink to &quot;Next-tier hint&quot;">​</a></h3><p>Every profile shows what&#39;s still needed for the next tier — e.g. <code>Gold → Platinum: rating ≥ 4.9, +50 completed jobs, on-time ≥ 98%</code>. No gamified carrot; just a concrete list so creators know exactly what moves the needle.</p><h2 id="hire-contract" tabindex="-1">Hire &amp; contract <a class="header-anchor" href="#hire-contract" aria-label="Permalink to &quot;Hire &amp; contract&quot;">​</a></h2><p>A 4-step stepper: <strong>Brief → Scope &amp; schedule → Contract → Pay &amp; start</strong>. The contract is CRAFT-standard with fields for parties, deliverable, format, revisions, delivery date, usage rights, and credit line. The payment summary breaks out:</p><ul><li><code>{words} × {rate}</code> → creator receives</li><li><code>Marketplace fee (15%)</code></li><li><strong>You pay</strong> total</li></ul><p>Funds are held in escrow via Stripe Connect Express&#39;s manual-capture PaymentIntent (single-mode contracts) or one PaymentIntent per milestone (milestone-mode). The seller&#39;s payout goes through Stripe&#39;s <code>transfer_data.destination</code> at capture; the platform fee comes off as <code>application_fee_amount</code>. Refunds, cancels, and dispute handling are first-class state-machine operations on the contract.</p><h2 id="backend-status" tabindex="-1">Backend status <a class="header-anchor" href="#backend-status" aria-label="Permalink to &quot;Backend status&quot;">​</a></h2><p>Marketplace runs as its own service in the <code>marketplace</code> Postgres schema, with ~150 endpoints across 17 route surfaces and 15 NATS workers (sanctions screening, watermark generation, attribution finalization, spotlight recompute, account purge, async data export, etc.). It deploys as a Helm subchart of CRAFT (<code>craft-marketplace-*</code> pods), reachable from the cluster at <code>marketplace-dev.mossworks.io</code> in dev environments.</p><p>Source: <a href="https://github.com/Mossworks-Labs/marketplace" target="_blank" rel="noreferrer">Mossworks-Labs/marketplace</a>.</p>',39))])}const y=i(c,[["render",h]]);export{k as __pageData,y as default};
